<template><div class="sc-design-field" :data-invalid="invalid || undefined"><label :for="controlId">{{ label }}<span v-if="required" aria-hidden="true">*</span></label><slot :control-id="controlId" :described-by="describedBy" /><p v-if="help" :id="helpId" class="sc-text-muted">{{ help }}</p><p v-if="error" :id="errorId" class="sc-design-field__error" role="alert">{{ error }}</p></div></template>
<script setup lang="ts">import { computed, useId } from 'vue'; const props=defineProps<{ label:string; fieldKey:string; required?:boolean; invalid?:boolean; help?:string; error?:string }>(); const suffix=useId(); const controlId=computed(()=>`sc-field-${props.fieldKey.replace(/[^A-Za-z0-9_-]/g,'-')}-${suffix}`); const helpId=computed(()=>`${controlId.value}-help`); const errorId=computed(()=>`${controlId.value}-error`); const describedBy=computed(()=>[props.help&&helpId.value,props.error&&errorId.value].filter(Boolean).join(' ')||undefined);</script>
<style scoped>.sc-design-field{display:grid;gap:var(--sc-product-space-1)}.sc-design-field>label{color:var(--sc-app-text-secondary);font-size:var(--sc-product-text-sm);font-weight:600}.sc-design-field__error{margin:0;color:var(--sc-app-danger-text);font-size:var(--sc-product-text-sm)}</style>
